('YBC_2020_consolidated_debt_0', 'YBC', 2020, 'consolidated', 'Ngân hàng TMCP Đầu tư và Phát triển Việt Nam - CN Yên Bái', 'short_term', 169949906797.0, NULL, 'Thế chấp toàn bộ giá trị phần xây lắp và máy móc thiết bị, phương tiện vận tải của nhà máy chế biến CaCO3; nhà máy xi măng lò quay; nhà máy xi măng lò đúng; văn phòng công ty; xí nghiệp khai thác đá thuộc Công ty CP xi măng khoáng sản Yên Bái.', NULL),
('YBC_2020_consolidated_debt_1', 'YBC', 2020, 'consolidated', 'Ngân hàng Nông nghiệp và phát triển nông thôn Việt Nam - CN huyện Yên Bình', 'short_term', 99987040913.0, NULL, 'Thế chấp tài sản là giá trị quyền khai thác khoáng sản (quyền khai thác mỏ) theo hợp đồng thế chấp tài sản số 110-2017/HĐTC ngày 18 tháng 10 năm 2017; Thế chấp tài sản là dây truyền máy móc thiết bị (Máy nghiền xi măng MB 35130) theo hợp đồng thế chấp tài sản số 111-2018/HĐTC ngày 08/11/2018.', NULL),
